refsection.programlisting:

global GROCERDIR;
// load the database small_db:
load(GROCERDIR+'\data\small_db.dat')
// extrapolate variables demmon with a 1% growth rate, time with a 1 increment and trim1
// (first quarter), with the values [1;0;0;0] over period ['2007q1';'2007q4']:
small_ext=tsmat_extrap(small_db,'demmon',['2007q1';'2007q4'],'growth rate',0.01,...
'time',['2007q1';'2007q4'],'delta rate',1,...
'trim1',['2007q1';'2007q4'],'level',[1;0;0;0],...
'petfx',['2007q1';'2007q4'],'av growth rate',8,...
'petfm',['2007q1';'2007q4'],'series','petfx');
// note here that the values of one variable can be exatrapolated by the values of an extrapolated variable
// provided that variable used for extrapolation has itself been put before the one to extrapolate
// check that the new values have been taken into account in the new database and that
// this is not the case for variable trim2:
prt_tsmat('level',['2006q1';'2007q4'],list('small_ext'),['demmon';'time';'trim1';'petfx';'petfm';'trim2'])
